import React, { useEffect, useMemo, useState } from "react";

function Admin({ apiBase = "http://localhost:8080", onFoodSaved }) {
  const [foods, setFoods] = useState([]);
  const [orders, setOrders] = useState([]);
  const [message, setMessage] = useState("");
  const [editingId, setEditingId] = useState(null);

  const [form, setForm] = useState({
    name: "",
    price: "",
    category: "",
    imageUrl: ""
  });

  useEffect(() => {
    loadFoods();
    loadOrders();
  }, []);

  async function loadFoods() {
    try {
      const response = await fetch(`${apiBase}/foods`);
      const data = await response.json();
      setFoods(Array.isArray(data) ? data : []);
    } catch (error) {
      setMessage("Could not load foods.");
    }
  }

  async function loadOrders() {
    try {
      const response = await fetch(`${apiBase}/orders`);
      const data = await response.json();
      setOrders(Array.isArray(data) ? data : []);
    } catch (error) {
      setOrders([]);
    }
  }

  const dashboardStats = useMemo(() => {
    const totalFoods = foods.length;
    const totalOrders = orders.length;
    const pendingOrders = orders.filter(
      (item) =>
        String(item.status || "").toLowerCase() === "pending" ||
        String(item.status || "").toLowerCase() === "preparing"
    ).length;
    const completedOrders = orders.filter((item) =>
      String(item.status || "").toLowerCase().includes("complete")
    ).length;

    return { totalFoods, totalOrders, pendingOrders, completedOrders };
  }, [foods, orders]);

  function handleChange(event) {
    const { name, value } = event.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  }

  function resetForm() {
    setEditingId(null);
    setForm({
      name: "",
      price: "",
      category: "",
      imageUrl: ""
    });
  }

  async function saveFood() {
    if (!form.name || !form.price || !form.category) {
      setMessage("Name, price, and category are required.");
      return;
    }

    const payload = {
      name: form.name,
      price: Number(form.price),
      category: form.category,
      imageUrl: form.imageUrl
    };

    const url = editingId ? `${apiBase}/foods/${editingId}` : `${apiBase}/foods`;
    const method = editingId ? "PUT" : "POST";

    try {
      const response = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload)
      });

      if (!response.ok) throw new Error("save failed");

      setMessage(editingId ? "Food updated successfully." : "Food added successfully.");
      resetForm();
      loadFoods();
      if (onFoodSaved) onFoodSaved();
    } catch (error) {
      setMessage("Could not save the food item.");
    }
  }

  function editFood(food) {
    setEditingId(food.id);
    setForm({
      name: food.name || "",
      price: food.price || "",
      category: food.category || "",
      imageUrl: food.imageUrl || ""
    });
  }

  async function deleteFood(id) {
    try {
      const response = await fetch(`${apiBase}/foods/${id}`, {
        method: "DELETE"
      });

      if (!response.ok) throw new Error("delete failed");

      setMessage("Food item deleted.");
      loadFoods();
      if (onFoodSaved) onFoodSaved();
    } catch (error) {
      setMessage("Could not delete the food item.");
    }
  }

  return (
    <div className="section-gap">
      <section className="content-card">
        <div className="section-title-row">
          <div>
            <h2>Admin Dashboard</h2>
            <p>Manage food items and track canteen activity.</p>
          </div>
        </div>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
            gap: "14px",
            marginBottom: "18px"
          }}
        >
          <div className="summary-card" style={{ padding: "16px" }}>
            <h3>Total Foods</h3>
            <p style={{ fontSize: "24px", fontWeight: "700", margin: 0 }}>
              {dashboardStats.totalFoods}
            </p>
          </div>

          <div className="summary-card" style={{ padding: "16px" }}>
            <h3>Total Orders</h3>
            <p style={{ fontSize: "24px", fontWeight: "700", margin: 0 }}>
              {dashboardStats.totalOrders}
            </p>
          </div>

          <div className="summary-card" style={{ padding: "16px" }}>
            <h3>Pending / Preparing</h3>
            <p style={{ fontSize: "24px", fontWeight: "700", margin: 0 }}>
              {dashboardStats.pendingOrders}
            </p>
          </div>

          <div className="summary-card" style={{ padding: "16px" }}>
            <h3>Completed</h3>
            <p style={{ fontSize: "24px", fontWeight: "700", margin: 0 }}>
              {dashboardStats.completedOrders}
            </p>
          </div>
        </div>

        {message && <div className="message-banner">{message}</div>}

        <div className="admin-form-grid">
          <input
            name="name"
            value={form.name}
            onChange={handleChange}
            placeholder="Food name"
          />
          <input
            name="price"
            value={form.price}
            onChange={handleChange}
            placeholder="Price"
            type="number"
          />
          <input
            name="category"
            value={form.category}
            onChange={handleChange}
            placeholder="Category"
          />
          <input
            name="imageUrl"
            value={form.imageUrl}
            onChange={handleChange}
            placeholder="Image URL (optional)"
          />
        </div>

        <div className="action-row top-space">
          <button className="primary-btn" onClick={saveFood}>
            {editingId ? "Update Food" : "Add Food"}
          </button>
          <button className="secondary-btn" onClick={resetForm}>
            Clear
          </button>
        </div>
      </section>

      <section className="section-gap">
        <div className="menu-grid">
          {foods.map((food) => (
            <div className="menu-card" key={food.id}>
              <img
                src={
                  food.imageUrl ||
                  "https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&w=900&q=80"
                }
                alt={food.name}
                className="food-image small"
              />

              <div className="menu-card-body">
                <div className="title-row">
                  <span className="food-category-tag">{food.category}</span>
                </div>

                <h3>{food.name}</h3>
                <p className="price">₹{food.price}</p>

                <div className="action-row">
                  <button className="secondary-btn" onClick={() => editFood(food)}>
                    Edit
                  </button>
                  <button className="danger-btn" onClick={() => deleteFood(food.id)}>
                    Delete
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}

export default Admin;
